[
 {
  "type": "header",
  "data": {
   "text": "Biometric Attendance",
   "subtext": "ZKTeco Device Integration",
   "col": 12
  }
 },
 {
  "type": "spacer",
  "data": {
   "col": 12
  }
 },
 {
  "type": "number_card",
  "data": {
   "label": "Connected Devices",
   "number": "frappe.db.count(\"Biometric Device\", {\"status\": \"Active\"})",
   "col": 3
  }
 },
 {
  "type": "number_card",
  "data": {
   "label": "Today's Punches",
   "number": "frappe.db.count(\"Biometric Attendance Log\", {\"timestamp\": [\">=\", frappe.utils.today()]})",
   "col": 3
  }
 },
 {
  "type": "number_card",
  "data": {
   "label": "Sync Failures (24h)",
   "number": "frappe.db.count(\"Biometric Sync Log\", {\"status\": \"Failed\", \"sync_start\": [\">=\", frappe.utils.add_days(frappe.utils.today(), -1)]})",
   "col": 3,
   "color": "#d63031"
  }
 },
 {
  "type": "number_card",
  "data": {
   "label": "Unmapped Users",
   "number": "frappe.db.sql(\"SELECT COUNT(DISTINCT device_user_id) FROM `tabBiometric Attendance Log` WHERE NOT EXISTS (SELECT 1 FROM `tabBiometric Employee Mapping` bem WHERE bem.biometric_user_id = `tabBiometric Attendance Log`.device_user_id AND bem.device = `tabBiometric Attendance Log`.device)\")[0][0]",
   "col": 3,
   "color": "#fdcb6e"
  }
 },
 {
  "type": "spacer",
  "data": {
   "col": 12
  }
 },
 {
  "type": "shortcut",
  "data": {
   "label": "Add Device",
   "doc_type": "Biometric Device",
   "col": 3
  }
 },
 {
  "type": "shortcut",
  "data": {
   "label": "Add Mapping",
   "doc_type": "Biometric Employee Mapping",
   "col": 3
  }
 },
 {
  "type": "shortcut",
  "data": {
   "label": "Sync All Devices",
   "action": "zkteco_attendance.api.sync_all_devices",
   "col": 3
  }
 },
 {
  "type": "shortcut",
  "data": {
   "label": "Auto Map Employees",
   "action": "zkteco_attendance.api.auto_map_employees",
   "col": 3
  }
 },
 {
  "type": "spacer",
  "data": {
   "col": 12
  }
 },
 {
  "type": "header",
  "data": {
   "text": "Quick Links",
   "subtext": "",
   "col": 12
  }
 },
 {
  "type": "card",
  "data": {
   "card_name": "Device Management",
   "col": 4
  }
 },
 {
  "type": "card",
  "data": {
   "card_name": "Employee Mapping",
   "col": 4
  }
 },
 {
  "type": "card",
  "data": {
   "card_name": "Sync Logs",
   "col": 4
  }
 },
 {
  "type": "spacer",
  "data": {
   "col": 12
  }
 },
 {
  "type": "header",
  "data": {
   "text": "Recent Sync Activity",
   "subtext": "",
   "col": 12
  }
 },
 {
  "type": "table",
  "data": {
   "table_name": "Recent Syncs",
   "doc_type": "Biometric Sync Log",
   "limit": 10,
   "col": 12
  }
 }
]
